// Tax4Us Social Media Agent - Content Analysis
const input = $input.first().json;
console.log("Tax4Us Social Media Agent - Content Analysis");

// Analyze content and determine platform strategy
const contentAnalysis = {
  source: input.source || "content_intelligence_agent",
  contentType: input.contentType || "blog_post",
  title: input.title || input.Keyword || "Tax Planning Tips",
  topic: input.topic || input.Keyword || "tax planning",
  targetAudience: input.targetAudience || "Israeli business owners",
  keywords: input.keywords || input.Keyword ? [input.Keyword] : ["tax planning", "israel", "business"],
  platforms: ["facebook", "linkedin"],
  contentStrategy: {
    facebook: {
      tone: "friendly",
      format: "visual",
      hashtags: ["#TaxTips", "#Israel", "#Business", "#Tax4Us"],
      optimalLength: "100-200 words"
    },
    linkedin: {
      tone: "professional",
      format: "text",
      hashtags: ["#TaxPlanning", "#BusinessStrategy", "#Israel", "#Tax4Us"],
      optimalLength: "200-300 words"
    }
  },
  timestamp: new Date().toISOString(),
  status: "content_analyzed"
};

return {
  json: {
    ...contentAnalysis,
    message: "Content analyzed for social media platforms",
    nextStep: "platform_specific_content_generation"
  }
};

parameters.prompt:
Create engaging Facebook content for Tax4Us based on the following specifications:

Title: {{ $json.title }}
Topic: {{ $json.topic }}
Target Audience: {{ $json.targetAudience }}
Keywords: {{ $json.keywords.join(", ") }}

Facebook Requirements:
- Tone: {{ $json.contentStrategy.facebook.tone }}
- Format: {{ $json.contentStrategy.facebook.format }}
- Length: {{ $json.contentStrategy.facebook.optimalLength }}
- Hashtags: {{ $json.contentStrategy.facebook.hashtags.join(", ") }}

Content Guidelines:
1. Start with an engaging hook or question
2. Provide valuable tax tips or insights
3. Include a clear call-to-action for Tax4Us services
4. Use emojis strategically for visual appeal
5. Make it shareable and relatable
6. Focus on Israeli business context
7. Include relevant hashtags naturally

Create content that encourages engagement, comments, and shares while positioning Tax4Us as the expert tax advisor for Israeli businesses.

Create professional LinkedIn content for Tax4Us based on the following specifications:

Title: {{ $json.title }}
Topic: {{ $json.topic }}
Target Audience: {{ $json.targetAudience }}
Keywords: {{ $json.keywords.join(", ") }}

LinkedIn Requirements:
- Tone: {{ $json.contentStrategy.linkedin.tone }}
- Format: {{ $json.contentStrategy.linkedin.format }}
- Length: {{ $json.contentStrategy.linkedin.optimalLength }}
- Hashtags: {{ $json.contentStrategy.linkedin.hashtags.join(", ") }}

Content Guidelines:
1. Start with a compelling business insight or statistic
2. Provide professional tax advice and industry analysis
3. Include thought leadership perspective
4. Add a professional call-to-action
5. Use LinkedIn's professional tone
6. Focus on business value and ROI
7. Include relevant professional hashtags
8. Encourage networking and discussion

Create content that positions Tax4Us as a thought leader in Israeli tax planning and business strategy.

