const facebookContent = $("Facebook Content Generation").item.json.text;
const imagePrompt = $("Facebook Image Prompt").item.json.text;
const analysis = $json;

const facebookPost = {
  platform: "facebook",
  content: facebookContent,
  imagePrompt: imagePrompt,
  hashtags: analysis.contentStrategy.facebook.hashtags,
  tone: analysis.contentStrategy.facebook.tone,
  format: analysis.contentStrategy.facebook.format,
  targetAudience: analysis.targetAudience,
  topic: analysis.topic,
  timestamp: new Date().toISOString(),
  status: "facebook_ready"
};

return {
  json: facebookPost
};

// Prepare LinkedIn post data
const linkedinContent = $("LinkedIn Content Generation").item.json.text;
