  hashtags: analysis.contentStrategy.linkedin.hashtags,
  tone: analysis.contentStrategy.linkedin.tone,
  format: analysis.contentStrategy.linkedin.format,
  targetAudience: analysis.targetAudience,
  topic: analysis.topic,
  timestamp: new Date().toISOString(),
  status: "linkedin_ready"
};

return {
  json: linkedinPost
};

